#include <bits/stdc++.h>
using namespace std;
const int N = 1000010;
int tr[N],n,a[N],m,vis[N],ans[N];
struct node
{
	int l,r,id;
} q[N];
bool cmp(node x,node y)
{
	return x.r<y.r;
}
int lowbit(int x)
{
	return x&-x;
}
void add(int x,int k)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		tr[i]+=k;
	}
}
int query(int x)
{
	int ans2=0;
	for(int i=x;i;i-=lowbit(i)) ans2+=tr[i];
	return ans2;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	cin>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>q[i].l>>q[i].r;
		q[i].id=i;
	}
	sort(q+1,q+1+m,cmp);
	int pow=1;
	for(int i=1;i<=m;i++)
	{
		for(int j=pow;j<=q[i].r;j++)
		{
			if(vis[a[j]])
			{
				add(vis[a[j]],-1);
				//cout<<"add-1:"<<vis[a[j]]<<'\n';
			}
			add(j,1);
			//cout<<"add1:"<<j<<'\n';
			vis[a[j]]=j;
		}
		pow=q[i].r+1;
		ans[q[i].id]=query(q[i].r)-query(q[i].l-1);
		//cout<<"id:"<<i<<"  q[i].l:"<<q[i].l<<"  q[i].r:"<<q[i].r<<"  Query (r):"<<query(q[i].r)<<"  Query(l-1):"<<query(q[i].l-1)<<"  ans:"<<ans[q[i].id]<<'\n';
	 } 
	 for(int i=1;i<=m;i++) cout<<ans[i]<<'\n';
	 return 0; 
}
